\section{Typeclass scaffolding for the representability assembly}
\label{sec:fga_pic_typeclass_scaffolding}

The five public declarations above are each phrased so that their single
mathematical obligation is isolated in a \emph{carrier}: a \(\Prop\)-valued
existence predicate together with a noncomputable extraction of the asserted
object. This section records, with a one-to-one Lean correspondence, each
carrier predicate, each extraction, and each existence witness. The carriers
are file-internal scaffolding for the public results; their substantive
mathematical content is the obligation analysed in
\cref{sec:fga_pic_sorry_closure_order}.

\subsection{Carriers for the sibling-chapter functors}
\label{subsec:fga_pic_functor_carriers}

\begin{definition}[Existence carrier for the relative Picard functor]
  \label{def:has_pic_sharp}
  \lean{AlgebraicGeometry.Scheme.PicScheme.HasPicSharp}
  The predicate \(\HasPicSharp(C)\) asserts that the category of presheaves of
  types on \((\Sch/k)^{op}\) admits at least one object intended to be the
  \'etale-sheafified relative Picard functor \(\Pic^\sharp_{(C/k)\et}\) of
  \cref{chap:Picard_RelPicFunctor}. It is the existence carrier that lets the
  public declarations of this chapter mention \(\Pic^\sharp_{(C/k)\et}\)
  before the A.1.c sibling chapter has committed to a specific construction.
\end{definition}

\begin{proof}
  Proved directly in Lean.
\end{proof}

\begin{definition}[The relative Picard functor as a carrier extraction]
  \label{def:pic_sharp_carrier}
  \lean{AlgebraicGeometry.Scheme.PicScheme.picSharp}
  \uses{def:has_pic_sharp}
  The presheaf \(\picSharp(C) : (\Sch/k)^{op} \to \Set\) is the object whose
  existence is asserted by \cref{def:has_pic_sharp}, extracted as a chosen
  witness. It is a file-internal stand-in for the functor pinned in
  \cref{chap:Picard_RelPicFunctor}; once that chapter lands, the extraction
  collapses to a re-export of \(\Pic^\sharp_{(C/k)\et}\).
\end{definition}

\begin{proof}
  Proved directly in Lean.
\end{proof}

\begin{definition}[Existence witness for the relative Picard functor]
  \label{def:inst_has_pic_sharp}
  \lean{AlgebraicGeometry.Scheme.PicScheme.instHasPicSharp}
  \uses{def:has_pic_sharp}
  The canonical instance recording that \cref{def:has_pic_sharp} holds for
  every smooth proper geometrically integral curve \(C/k\). Its substantive
  discharge --- exhibiting the actual \'etale sheafification rather than a
  tautological witness --- is analysed as Sorry~1 in
  \cref{subsec:sorry_has_pic_sharp}.
\end{definition}

\begin{proof}
  Proved directly in Lean; the semantic discharge is the obligation of
  \cref{subsec:sorry_has_pic_sharp}.
\end{proof}

\begin{definition}[Existence carrier for the relative-divisor functor]
  \label{def:has_div_functor}
  \lean{AlgebraicGeometry.Scheme.PicScheme.HasDivFunctor}
  The predicate \(\HasDivFunctor(C)\) asserts that the category of presheaves
  of types on \((\Sch/k)^{op}\) admits at least one object intended to be the
  relative-effective-divisor functor \(\mathrm{Div}_{C/k}\), sending a
  \(k\)-scheme \(T\) to the set of relative effective Cartier divisors on
  \(C \times_k T\) flat over \(T\). It is the existence carrier for
  \(\mathrm{Div}_{C/k}\) ahead of the A.2.b sibling chapter.
\end{definition}

\begin{proof}
  Proved directly in Lean.
\end{proof}

\begin{definition}[The relative-divisor functor as a carrier extraction]
  \label{def:div_functor_carrier}
  \lean{AlgebraicGeometry.Scheme.PicScheme.divFunctor}
  \uses{def:has_div_functor}
  The presheaf \(\mathrm{Div}_{C/k} : (\Sch/k)^{op} \to \Set\) is the object
  whose existence is asserted by \cref{def:has_div_functor}, extracted as a
  chosen witness. It is the open subfunctor of the Hilbert scheme cut out by
  the effective-divisor criterion of \cref{lem:line_bundle_quot_correspondence};
  once \cref{chap:Picard_QuotScheme} lands, the extraction collapses to a
  re-export.
\end{definition}

\begin{proof}
  Proved directly in Lean.
\end{proof}

\begin{definition}[Existence witness for the relative-divisor functor]
  \label{def:inst_has_div_functor}
  \lean{AlgebraicGeometry.Scheme.PicScheme.instHasDivFunctor}
  \uses{def:has_div_functor}
  The canonical instance recording that \cref{def:has_div_functor} holds for
  every such curve \(C/k\). Its substantive discharge is analysed as Sorry~2
  in \cref{subsec:sorry_has_div_functor}.
\end{definition}

\begin{proof}
  Proved directly in Lean; the semantic discharge is the obligation of
  \cref{subsec:sorry_has_div_functor}.
\end{proof}

\subsection{Carrier for the Abel map}
\label{subsec:fga_pic_abel_map_carrier}

\begin{definition}[Existence carrier for the Abel map]
  \label{def:has_abel_map}
  \lean{AlgebraicGeometry.Scheme.PicScheme.HasAbelMap}
  \uses{def:div_functor_carrier, def:pic_sharp_carrier}
  The predicate \(\HasAbelMap(C)\) asserts the existence of a natural
  transformation of presheaves \(\mathrm{Div}_{C/k} \to \Pic^\sharp_{(C/k)\et}\),
  i.e.\ a candidate Abel map between the carrier functors of
  \cref{def:div_functor_carrier} and \cref{def:pic_sharp_carrier}.
\end{definition}

\begin{proof}
  Proved directly in Lean.
\end{proof}

\begin{definition}[Existence witness for the Abel map]
  \label{def:inst_has_abel_map}
  \lean{AlgebraicGeometry.Scheme.PicScheme.instHasAbelMap}
  \uses{def:has_abel_map}
  The canonical instance recording that \cref{def:has_abel_map} holds for every
  such curve \(C/k\); the extracted natural transformation is the Abel map of
  \cref{lem:line_bundle_quot_correspondence}. Its substantive discharge is
  analysed as Sorry~3 in \cref{subsec:sorry_has_abel_map}.
\end{definition}

\begin{proof}
  Proved directly in Lean; the semantic discharge is the obligation of
  \cref{subsec:sorry_has_abel_map}.
\end{proof}

\subsection{Carrier for the smooth-proper quotient}
\label{subsec:fga_pic_quotient_carrier}

\begin{definition}[Conclusion carrier for the smooth-proper quotient lemma]
  \label{def:has_smooth_proper_quotient}
  \lean{AlgebraicGeometry.Scheme.PicScheme.HasSmoothProperQuotient}
  For a morphism \(\alpha : Z \to P\) of presheaves of types on
  \((\Sch/k)^{op}\), the predicate \(\HasSmoothProperQuotient(\alpha)\) asserts
  that the target \(P\) is representable. It packages the conclusion of the
  Altman--Kleiman smooth-proper quotient lemma \cref{lem:smooth_proper_quotient}
  under its four standing hypotheses.
\end{definition}

\begin{proof}
  Proved directly in Lean.
\end{proof}

\begin{definition}[Existence witness for the smooth-proper quotient]
  \label{def:inst_has_smooth_proper_quotient}
  \lean{AlgebraicGeometry.Scheme.PicScheme.instHasSmoothProperQuotient}
  \uses{def:has_smooth_proper_quotient}
  The canonical instance recording that \cref{def:has_smooth_proper_quotient}
  holds for every morphism \(\alpha\) satisfying the hypotheses of
  \cref{lem:smooth_proper_quotient}. Its substantive discharge --- the
  Altman--Kleiman effective-equivalence-relation descent together with the
  EGA~IV~8.11.5 closed-immersion step --- is analysed as Sorry~4 in
  \cref{subsec:sorry_smooth_proper_quotient}.
\end{definition}

\begin{proof}
  Proved directly in Lean; the semantic discharge is the obligation of
  \cref{subsec:sorry_smooth_proper_quotient}.
\end{proof}

\subsection{Carriers for the Picard scheme and its structure}
\label{subsec:fga_pic_scheme_carriers}

\begin{definition}[Existence carrier for the Picard scheme]
  \label{def:has_pic_scheme}
  \lean{AlgebraicGeometry.Scheme.HasPicScheme}
  \uses{def:pic_sharp_carrier}
  The predicate \(\HasPicScheme(C)\) asserts that there exists a \(k\)-scheme
  \(X\) carrying a representability witness for \(\Pic^\sharp_{(C/k)\et}\); in
  other words, that the Picard scheme \(\Pic_{C/k}\) exists. It is the
  existence carrier from which \cref{def:pic_scheme} extracts the representing
  object.
\end{definition}

\begin{proof}
  Proved directly in Lean.
\end{proof}

\begin{definition}[Existence witness for the Picard scheme]
  \label{def:inst_has_pic_scheme}
  \lean{AlgebraicGeometry.Scheme.instHasPicScheme}
  \uses{def:has_pic_scheme}
  The canonical instance recording that \cref{def:has_pic_scheme} holds for
  every smooth proper geometrically integral curve \(C/k\). Its substantive
  discharge --- the four-step FGA construction of
  \cref{thm:fga_pic_representability}, gated on the Riemann--Roch substrate ---
  is analysed as Sorry~5 in \cref{subsec:sorry_has_pic_scheme}.
\end{definition}

\begin{proof}
  Proved directly in Lean; the semantic discharge is the obligation of
  \cref{subsec:sorry_has_pic_scheme}.
\end{proof}

\begin{definition}[Carrier: \(\Pic_{C/k}\) represents \(\Pic^\sharp_{(C/k)\et}\)]
  \label{def:pic_sharp_representable}
  \lean{AlgebraicGeometry.Scheme.PicScheme.PicSharpRepresentable}
  \uses{def:pic_sharp_carrier, def:pic_scheme}
  The predicate \(\PicSharpRepresentable(C)\) asserts that the specific scheme
  \(\Pic_{C/k}\) of \cref{def:pic_scheme} is a representing object for
  \(\Pic^\sharp_{(C/k)\et}\). It is the carrier from which the representability
  witness \cref{thm:fga_pic_representability} is extracted.
\end{definition}

\begin{proof}
  Proved directly in Lean.
\end{proof}

\begin{definition}[Existence witness for the representability identification]
  \label{def:inst_pic_sharp_representable}
  \lean{AlgebraicGeometry.Scheme.PicScheme.instPicSharpRepresentable}
  \uses{def:pic_sharp_representable}
  The canonical instance recording that \cref{def:pic_sharp_representable} holds
  for every such curve \(C/k\). Its substantive discharge is analysed as
  Sorry~6 in \cref{subsec:sorry_pic_sharp_representable}.
\end{definition}

\begin{proof}
  Proved directly in Lean; the semantic discharge is the obligation of
  \cref{subsec:sorry_pic_sharp_representable}.
\end{proof}

\begin{definition}[Existence carrier for the group-object structure]
  \label{def:pic_scheme_group_object}
  \lean{AlgebraicGeometry.Scheme.PicScheme.PicSchemeGroupObject}
  \uses{def:pic_scheme}
  The predicate \(\PicSchemeGroupObject(C)\) asserts that the Picard scheme
  \(\Pic_{C/k}\) of \cref{def:pic_scheme} carries a group-object structure in
  the category of \(k\)-schemes. It is the carrier underlying
  \cref{thm:pic_is_group_scheme}.
\end{definition}

\begin{proof}
  Proved directly in Lean.
\end{proof}

\begin{definition}[Existence witness for the group-object structure]
  \label{def:inst_pic_scheme_group_object}
  \lean{AlgebraicGeometry.Scheme.PicScheme.instPicSchemeGroupObject}
  \uses{def:pic_scheme_group_object}
  The canonical instance recording that \cref{def:pic_scheme_group_object}
  holds for every such curve \(C/k\); the extracted structure is the group
  scheme of \cref{thm:pic_is_group_scheme}. Its substantive discharge --- the
  Yoneda transport of the tensor-product abelian-group operations --- is
  analysed as Sorry~7 in \cref{subsec:sorry_pic_scheme_group_object}.
\end{definition}

\begin{proof}
  Proved directly in Lean; the semantic discharge is the obligation of
  \cref{subsec:sorry_pic_scheme_group_object}.
\end{proof}

